import{_ as t}from"./chunks/Inspector.C6Ut5Zza.js";import{_ as o,c as n,o as s,ag as a}from"./chunks/framework.Dnsuz9ka.js";const u=JSON.parse('{"title":"Inspect","description":"","frontmatter":{"title":"Inspect"},"headers":[],"relativePath":"props/inspect.md","filePath":"props/inspect.md"}'),r={name:"props/inspect.md"};function i(l,e,p,c,h,g){return s(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="inspect-mode-pick-a-component-on-the-page" tabindex="-1">Inspect mode (pick a component on the page) <a class="header-anchor" href="#inspect-mode-pick-a-component-on-the-page" aria-label="Permalink to &quot;Inspect mode (pick a component on the page)&quot;">​</a></h1><p><img src="'+t+'" alt="Инспектор"></p><p><strong>Inspect</strong> on the <strong>Props</strong> tab lets you pick UI on the <strong>page</strong> and, after click, narrow the component list to the subtree tied to that node — similar to picking an element in browser DevTools, but the result is <strong>filtering the Props table</strong>, not opening the DOM tree.</p><p>Overview: <a href="/qa-tools/docs/props/general.html">Props overview</a>.</p><hr><h2 id="start-and-stop" tabindex="-1">Start and stop <a class="header-anchor" href="#start-and-stop" aria-label="Permalink to &quot;Start and stop&quot;">​</a></h2><p>The <strong>Inspect</strong> control (pointer icon) lives on the <strong>Props</strong> toolbar and enables picking an element to filter components.</p><p>Before activation the component list <strong>refreshes</strong> so the tree matches the page.</p><p>By default <strong>Inspect</strong> temporarily <strong>hides</strong> the inspector overlay so it does not cover the page. Change this under <strong>Options → Inspect Mode → Hide overlay while inspecting</strong>.</p><p>Clicking <strong>Inspect</strong> again stops picking <strong>without</strong> clearing an applied filter.</p><p><strong>Escape</strong> cancels picking without selecting.</p><p>Switching tabs or closing the panel resets pick mode.</p><hr><h2 id="on-page-behavior" tabindex="-1">On-page behavior <a class="header-anchor" href="#on-page-behavior" aria-label="Permalink to &quot;On-page behavior&quot;">​</a></h2><p>With Inspect, pointer moves and clicks are handled <strong>above</strong> normal page behavior, including elements that usually ignore clicks.</p><p>Selection binds to the nearest DOM node linked to a <strong>Vue instance</strong>.</p><p>While moving the pointer, the element under it <strong>highlights</strong> and a <strong>tooltip</strong> may show:</p><ul><li>component name;</li><li>root element summary (tag, class fragment or <code>id</code>);</li><li>props count;</li><li>nested component count.</li></ul><p>Tooltip light/dark follows inspector theme.</p><p><strong>Vue Inspector</strong> UI (overlay, chevron, Inspect helpers) is excluded from picking.</p><p>If <strong>Hide overlay while inspecting</strong> is on, the UI returns after pick or cancel.</p><hr><h2 id="after-you-pick" tabindex="-1">After you pick <a class="header-anchor" href="#after-you-pick" aria-label="Permalink to &quot;After you pick&quot;">​</a></h2><p>When a page element is chosen:</p><ul><li>Inspect mode ends;</li><li>the <strong>Props</strong> table keeps components for that <strong>root</strong> subtree;</li><li>a <strong>Filtered</strong> chip shows the list is scoped.</li></ul><p>Click <strong>Filtered</strong> to clear the filter and reload the full list.</p><p>Starting Inspect again with a filter active lets you pick another root and replace the scope.</p><hr><h2 id="limits-and-notes" tabindex="-1">Limits and notes <a class="header-anchor" href="#limits-and-notes" aria-label="Permalink to &quot;Limits and notes&quot;">​</a></h2><ul><li>If there is no Vue-related node under the cursor, selection may not filter.</li><li>Deep DOM may resolve to the nearest component, not the visually expected level.</li><li>Inspect only affects the component list; <strong>favorites</strong>, <strong>blacklist</strong>, and <strong>search</strong> still apply on top.</li></ul><p>More: <a href="/qa-tools/docs/props/favorite.html">Favorites</a>, <a href="/qa-tools/docs/props/blacklist.html">Blacklist</a>.</p><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/props/general.html">Props overview</a></li><li><a href="/qa-tools/docs/props/favorite.html">Favorites</a></li><li><a href="/qa-tools/docs/props/blacklist.html">Blacklist</a></li></ul>',34)])])}const f=o(r,[["render",i]]);export{u as __pageData,f as default};
